import React from "react";

export default function Header({
  // estado
  query,
  setQuery,
  category,
  setCategory,
  filters,
  setFilters,
  filteredCount,

  // UI state
  isMobile,
  searchOpen,
  setSearchOpen,
  openPanel,
  setOpenPanel,

  // acciones externas
  onLogoClick,
  onContactClick,
}) {
  return (
    <div
      style={{
        background: "#fff",
        padding: "12px 20px",
        display: "flex",
        justifyContent: "space-between",
        alignItems: "center",
        position: "relative",
        zIndex: 100,
      }}
    >
      {/* LOGO */}
      <img
        src="/logo.png"
        alt="Marist-Art"
        style={{
          height: "40px",
          cursor: "pointer",
          opacity: 0.9,
        }}
        onClick={onLogoClick}
      />

      {/* CENTRO */}
      <div
        style={{
          display: "flex",
          alignItems: "center",
          gap: "16px",
          flex: 1,
          justifyContent: "center",
        }}
      >
        {!isMobile ? (
          <>
            {[
              { key: "todas", label: "Todas" },
              { key: "ilustracion", label: "Ilustración" },
              { key: "diseno", label: "Diseño" },
            ].map((cat) => {
              const active = category === cat.key;

              return (
                <span
                  key={cat.key}
                  onClick={() => {
                    setQuery("");
                    setFilters([]);
                    setCategory(cat.key);
                  }}
                  style={{
                    cursor: "pointer",
                    color: active ? "#111" : "#aaa",
                    fontWeight: active ? "600" : "400",
                    fontSize: "13px",
                    fontStyle: "italic",
                  }}
                >
                  {cat.label}
                </span>
              );
            })}

            <span
              onClick={onContactClick}
              style={{
                cursor: "pointer",
                color: "#aaa",
                fontSize: "13px",
                fontStyle: "italic",
              }}
            >
              Contacto
            </span>
          </>
        ) : (
          <button
            onClick={() =>
              setOpenPanel(openPanel === "menu" ? null : "menu")
            }
            style={{
              border: "none",
              background: "transparent",
              fontSize: "20px",
              cursor: "pointer",
            }}
          >
            ☰
          </button>
        )}
      </div>

      {/* DERECHA */}
      <div style={{ display: "flex", alignItems: "center", gap: "12px" }}>
        {!isMobile && (
          <span
            style={{
              fontSize: "12px",
              color: "#888",
              fontStyle: "italic",
            }}
          >
            {filteredCount} results
          </span>
        )}

        <button
          onClick={() => setSearchOpen(true)}
          style={{
            border: "none",
            background: "transparent",
            fontSize: "18px",
            cursor: "pointer",
          }}
        >
          🔍
        </button>
      </div>

      {/* SEARCH */}
      {searchOpen && (
        <>
          <div
            onClick={() => setSearchOpen(false)}
            style={{
              position: "fixed",
              inset: 0,
              zIndex: 200,
            }}
          />

          <div
            onClick={(e) => e.stopPropagation()}
            style={{
              position: "absolute",
              top: "100%",
              right: "20px",
              background: "#fff",
              border: "1px solid #eee",
              borderRadius: "12px",
              padding: "12px",
              zIndex: 300,
              width: "280px",
            }}
          >
            <input
              autoFocus
              value={query}
              onChange={(e) => setQuery(e.target.value)}
              placeholder="Buscar..."
              style={{
                width: "100%",
                border: "none",
                outline: "none",
              }}
            />
          </div>
        </>
      )}
    </div>
  );
}
